public class ShareReceiverActivity extends AppCompatActivity {

    private TextView textView;
    private LinearLayout imagesContainer;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        setTitle("Shared Content");

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(dp(16), dp(16), dp(16), dp(16));

        TextView headerText = new TextView(this);
        headerText.setTextSize(18f);
        headerText.setText("Text");
        headerText.setPadding(0, 0, 0, dp(8));
        root.addView(headerText, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        textView = new TextView(this);
        textView.setTextSize(16f);
        textView.setMovementMethod(new ScrollingMovementMethod());
        textView.setTextIsSelectable(true);
        textView.setMinLines(3);
        textView.setPadding(dp(12), dp(12), dp(12), dp(12));
        textView.setBackgroundColor(0x11000000);

        root.addView(textView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        TextView headerImages = new TextView(this);
        headerImages.setTextSize(18f);
        headerImages.setText("Images");
        headerImages.setPadding(0, dp(16), 0, dp(8));
        root.addView(headerImages, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        ScrollView scrollView = new ScrollView(this);
        imagesContainer = new LinearLayout(this);
        imagesContainer.setOrientation(LinearLayout.VERTICAL);
        scrollView.addView(imagesContainer, new ScrollView.LayoutParams(
                ScrollView.LayoutParams.MATCH_PARENT,
                ScrollView.LayoutParams.WRAP_CONTENT
        ));

        root.addView(scrollView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                0,
                1f
        ));

        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(@Nullable Intent intent) {
        textView.setText("");
        imagesContainer.removeAllViews();

        if (intent == null) return;

        String action = intent.getAction();
        String type = intent.getType();

        StringBuilder textBuilder = new StringBuilder();

        if (Intent.ACTION_SEND.equals(action)) {
            if (type != null && type.startsWith("text/")) {
                String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
                String subject = intent.getStringExtra(Intent.EXTRA_SUBJECT);
                if (subject != null && !subject.isEmpty()) {
                    textBuilder.append(subject).append("\n\n");
                }
                if (sharedText != null) {
                    textBuilder.append(sharedText);
                }
            } else if (type != null && type.startsWith("image/")) {
                Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
                if (imageUri != null) addImage(imageUri);
                String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
                if (sharedText != null && !sharedText.isEmpty()) {
                    textBuilder.append(sharedText);
                }
            } else {
                extractFromClipData(intent, textBuilder);
            }
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
            if (type != null && type.startsWith("image/")) {
                ArrayList<Uri> imageUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
                if (imageUris != null) {
                    for (Uri uri : imageUris) addImage(uri);
                } else {
                    extractFromClipData(intent, textBuilder);
                }
                String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
                if (sharedText != null && !sharedText.isEmpty()) {
                    if (textBuilder.length() > 0) textBuilder.append("\n\n");
                    textBuilder.append(sharedText);
                }
            } else {
                extractFromClipData(intent, textBuilder);
            }
        } else {
            extractFromClipData(intent, textBuilder);
        }

        if (textBuilder.length() == 0) {
            textView.setText("(No text shared)");
            textView.setAlpha(0.7f);
        } else {
            textView.setText(textBuilder.toString());
            textView.setAlpha(1f);
        }

        if (imagesContainer.getChildCount() == 0) {
            TextView empty = new TextView(this);
            empty.setText("(No images shared)");
            empty.setAlpha(0.7f);
            empty.setGravity(Gravity.CENTER_HORIZONTAL);
            imagesContainer.addView(empty, new LinearLayout.LayoutParams(
                    LinearLayout.LayoutParams.MATCH_PARENT,
                    LinearLayout.LayoutParams.WRAP_CONTENT
            ));
        }
    }

    private void extractFromClipData(Intent intent, StringBuilder textBuilder) {
        ClipData clipData = intent.getClipData();
        if (clipData == null) return;

        List<Uri> imageUris = new ArrayList<>();
        for (int i = 0; i < clipData.getItemCount(); i++) {
            ClipData.Item item = clipData.getItemAt(i);

            CharSequence cs = item.getText();
            if (cs != null && cs.length() > 0) {
                if (textBuilder.length() > 0) textBuilder.append("\n");
                textBuilder.append(cs);
            }

            Uri uri = item.getUri();
            if (uri != null) {
                String mime = getContentResolver().getType(uri);
                if (mime != null && mime.startsWith("image/")) {
                    imageUris.add(uri);
                } else {
                    if (textBuilder.length() > 0) textBuilder.append("\n");
                    textBuilder.append(uri.toString());
                }
            }
        }

        for (Uri uri : imageUris) addImage(uri);
    }

    private void addImage(Uri uri) {
        ImageView imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        imageView.setBackgroundColor(0x11000000);
        imageView.setPadding(dp(8), dp(8), dp(8), dp(8));

        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        );
        lp.bottomMargin = dp(12);

        imagesContainer.addView(imageView, lp);

        Bitmap bitmap = decodeBitmap(uri, 2048, 2048);
        if (bitmap != null) {
            imageView.setImageBitmap(bitmap);
        } else {
            imageView.setImageResource(android.R.drawable.ic_menu_report_image);
        }

        TextView uriView = new TextView(this);
        uriView.setText(uri.toString());
        uriView.setTextIsSelectable(true);
        uriView.setTextSize(12f);
        uriView.setAlpha(0.75f);
        uriView.setPadding(0, 0, 0, dp(12));
        imagesContainer.addView(uriView, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));
    }

    @Nullable
    private Bitmap decodeBitmap(Uri uri, int reqWidth, int reqHeight) {
        ContentResolver resolver = getContentResolver();

        try (InputStream is1 = resolver.openInputStream(uri)) {
            if (is1 == null) return null;
            BitmapFactory.Options opts = new BitmapFactory.Options();
            opts.inJustDecodeBounds = true;
            BitmapFactory.decodeStream(is1, null, opts);

            int inSampleSize = 1;
            int height = opts.outHeight;
            int width = opts.outWidth;
            if (height > reqHeight || width > reqWidth) {
                int halfHeight = height / 2;
                int halfWidth = width / 2;
                while ((halfHeight / inSampleSize) >= reqHeight && (halfWidth / inSampleSize) >= reqWidth) {
                    inSampleSize *= 2;
                }
            }

            BitmapFactory.Options opts2 = new BitmapFactory.Options();
            opts2.inSampleSize = Math.max(1, inSampleSize);
            opts2.inPreferredConfig = Bitmap.Config.ARGB_8888;

            try (InputStream is2 = resolver.openInputStream(uri)) {
                if (is2 == null) return null;
                return BitmapFactory.decodeStream(is2, null, opts2);
            }
        } catch (Exception e) {
            return null;
        }
    }

    private int dp(int v) {
        float d = getResources().getDisplayMetrics().density;
        return Math.round(v * d);
    }
}

